const { session_id, message, now } = $items("Normalize Input")[0].json;

const session = {
  session_id,
  created_at: now,
  updated_at: now,
  stage: "start",
  lead: { name: null, email: null, whatsapp: null },
  messages: []
};

if (message) {
  session.messages.push({ role: "user", text: message, ts: now });
}

return [{ json: { session_id, session } }];

const input = items[0].json;

// ===== Detecta estrutura =====
const body = input.body || {};
const messageData = body.message || {};
const conversation = body.conversation || {};

// ===== 1. SESSION ID (prioridade múltipla) =====
const session_id =
  conversation.jid ||
  messageData.jid ||
  input.sessionId ||
  input.session_id ||
  "unknown_session";

// ===== 2. TEXTO DA MENSAGEM =====
let message =
  messageData.text ||
  input.chatInput ||
  "";

// ===== 3. MEDIA URL =====
let media_url = null;

if (messageData.media && messageData.media.url) {
  const host = "https://myn8n.seommerce.shop";
  media_url = host + messageData.media.url;
}

// ===== 4. DADOS EXTRAS =====
const pushName =
  messageData.pushName ||
  "Cliente";

const messageType =
  messageData.type ||
  (input.chatInput ? "text" : "unknown");

const now = new Date().toISOString();

// ===== OUTPUT =====
return [
  {
    json: {
      session_id,
      message,
      media_url,
      messageType,
      pushName,
      now
    }
  }
];

// ================================
// INPUT
// ================================
const norm = $items("Normalize Input")?.[0]?.json ?? {};
const row = items[0].json;

const now = norm.now || new Date().toISOString();

// ================================
// HELPERS
// ================================
function safeJsonParse(value, fallback) {
  if (typeof value !== "string") return value ?? fallback;
  try {
    return JSON.parse(value);
  } catch {
    return fallback;
  }
}

function isFilled(v) {
  return v !== null && v !== undefined && String(v).trim() !== "";
}

// ================================
// LEAD
// ================================
let lead = safeJsonParse(row.lead, {});
if (typeof lead !== "object" || lead === null) lead = {};

// ================================
// BUSINESS
// ================================
let business = safeJsonParse(row.business, {});
if (typeof business !== "object" || business === null) business = {};

// ================================
// CONTEXT
// ================================
let context = safeJsonParse(row.context, {});
if (typeof context !== "object" || context === null) context = {};

// ================================
// MESSAGES (ROBUSTO)
// ================================
let messages = [];

// Caso 1: array já válido
if (Array.isArray(row.messages)) {
  messages = row.messages;
}

// Caso 2: JSON serializado
else if (
  typeof row.messages === "string" &&
  row.messages.trim().startsWith("[")
) {
  messages = safeJsonParse(row.messages, []);
}

// Caso 3: texto puro (mensagem antiga)
else if (typeof row.messages === "string" && row.messages.trim() !== "") {
  messages = [
    {
      role: "assistant",
      text: row.messages,
      ts: row.updatedAt || row.updated_at || now
    }
  ];
}

// ================================
// ANEXA NOVA MENSAGEM DO USUÁRIO
// ================================
if (norm.message && typeof norm.message === "string") {
  messages.push({
    role: "user",
    text: norm.message,
    ts: now
  });
}

// ================================
// LAST ACTION
// ================================
const last_action = norm.last_action || row.last_action || null;

// ================================
// STAGE DETECTION (REGRA DE NEGÓCIO)
// ================================
let nextStage = row.stage || "start";

// Se TODAS as infos do collect_context estiverem preenchidas → qualify
if (
  isFilled(lead?.name) &&
  isFilled(business?.business_type) &&
  isFilled(context?.main_pain) &&
  isFilled(context?.desired_solution) &&
  isFilled(context?.current_process) &&
  isFilled(context?.urgency) &&
  isFilled(context?.budget_hint)
) {
  nextStage = "qualify";
}

// ================================
// SESSION FINAL
// ================================
const session = {
  session_id: row.session_id,
  created_at: row.created_at, // nunca muda
  updated_at: now,
  stage: nextStage,
  last_action,
  lead,
  business,
  context,
  messages
};

// ================================
// OUTPUT
// ================================
return [
  {
    json: {
      session_id: row.session_id,
      session
    }
  }
];

// ================================
// ORIGEM PRINCIPAL: Data Tables
// ================================
const row = items[0].json;

// ================================
// ORIGEM DA ÚLTIMA MENSAGEM: Webhook
// ================================
const webhook = $('webhook').first().json;

// ---------- helper: parse seguro ----------
function safeParse(value, fallback) {
  if (typeof value === "string") {
    try {
      return JSON.parse(value);
    } catch (e) {
      return fallback;
    }
  }
  return value ?? fallback;
}

// ---------- Parse dos campos principais ----------
const messages = Array.isArray(safeParse(row.messages, []))
  ? safeParse(row.messages, [])
  : [];

const stage = row.stage ?? null;

// ================================
// ÚLTIMA MENSAGEM DO USUÁRIO
// ================================
let last_user_message = null;

if (webhook?.chatInput) {
  last_user_message = webhook.chatInput;
} else if (webhook?.body?.message?.text) {
  last_user_message = webhook.body.message.text;
}

// Fallback: pega do histórico salvo na sessão, se necessário
if (!last_user_message) {
  const userMessages = messages.filter(m => m.role === "user");
  last_user_message =
    userMessages.length > 0
      ? userMessages[userMessages.length - 1].text
      : null;
}

// ---------- Última mensagem do assistente ----------
let last_assistant_message = null;
for (let i = messages.length - 1; i >= 0; i--) {
  if (messages[i].role === "assistant") {
    last_assistant_message = messages[i].text;
    break;
  }
}

// ---------- Sessão ----------
const session = {
  session_id: row.session_id,
  created_at: row.created_at,
  updated_at: row.updated_at,
  stage,
  peca: row.peca ?? null,
  servico: row.servico ?? null,
  preferencia_data: row.preferencia_data ?? null,
  preferencia_periodo: row.preferencia_periodo ?? null,
  horario: row.horario ?? null,
  messages
};

// ---------- OUTPUT FINAL ----------
return [
  {
    json: {
      session,
      last_user_message,
      last_assistant_message
    }
  }
];

// Pega o item do node "resposta concatenada"
const row = $('resposta concatenada').first().json;

// Pega messages corretos dentro da sessão
let messages = row.session?.messages;
if (!Array.isArray(messages)) {
  messages = [];
}

// Próxima stage após envio da welcome
const next_stage = "collect_context";

// Pergunta inicial
const reply = "Olá! 😊 Ateliê Careliz ✂️🧵\n\nQual peça você deseja ajustar?\n\nDigite o número correspondente:\n\n1️⃣ Calça\n2️⃣ Camisa\n3️⃣ Vestido\n4️⃣ Saia\n5️⃣ Shorts\n6️⃣ Jaqueta\n7️⃣ Outro\n\n✍️ Responda apenas com o número.";

// Adiciona resposta do assistente ao histórico existente
messages.push({
  role: "assistant",
  text: reply,
  ts: new Date().toISOString()
});

// Atualiza sessão
const session = {
  ...row.session,
  messages,
  stage: next_stage,
  updated_at: new Date().toISOString()
};

return [
  {
    json: {
      ...row,
      action: "reply",
      reply,
      next_stage,
      session
    }
  }
];

const items = $input.all();

// pega o primeiro item do node "calça"
const baseItems = $items("calça");
const baseRow = Array.isArray(baseItems) && baseItems.length > 0
  ? baseItems[0].json
  : {};

// peça
const pieceType = items[0]?.json?.piece_type || baseRow["peça"] || "peça";

// formatação bonita
function formatLabel(text) {
  return String(text || "")
    .replaceAll("_", " ")
    .replace(/\b\w/g, l => l.toUpperCase());
}

// emojis
const baseEmojis = ["1️⃣","2️⃣","3️⃣","4️⃣","5️⃣","6️⃣","7️⃣","8️⃣","9️⃣","🔟"];

function getEmoji(index) {
  const number = index + 1;

  if (number <= 10) {
    return baseEmojis[index];
  }

  return String(number)
    .split("")
    .map(d => baseEmojis[Number(d) - 1] || d)
    .join("");
}

// remove duplicados por service_type
const uniqueMap = new Map();

for (const item of items) {
  const row = item.json;
  const serviceKey = String(row.service_type || "").trim().toLowerCase();

  if (!serviceKey) continue;

  // mantém apenas a primeira ocorrência de cada serviço
  if (!uniqueMap.has(serviceKey)) {
    uniqueMap.set(serviceKey, row);
  }
}

// transforma em array e ordena
const services = Array.from(uniqueMap.values()).sort(
  (a, b) => Number(a.id_servico) - Number(b.id_servico)
);

// lista dos serviços
const serviceList = services
  .map((s, index) => `${getEmoji(index)} ${formatLabel(s.service_type)}`)
  .join("\n\n");

// mensagem final
const reply = `Qual ajuste você quer fazer na sua ${pieceType}?

${serviceList}

━━━━━━━━━━━━━━━
📩 Como responder:
Digite apenas o número da opção desejada.
━━━━━━━━━━━━━━━`;

return [
  {
    json: {
      ...baseRow,
      reply
    }
  }
];

const row = items[0].json;

// mensagens da sessão
const messages = Array.isArray(row.session?.messages) ? row.session.messages : [];

// só mensagens do usuário
const userMessages = messages
  .filter(m => m.role === "user" && m.text != null)
  .map(m => String(m.text).trim())
  .filter(Boolean);

// função para extrair número da mensagem
function extractNumber(text) {
  const match = String(text).match(/\d+/);
  return match ? Number(match[0]) : null;
}

// 2ª mensagem do usuário = escolha da peça
const secondUserMessage = userMessages[1] ?? null;
const id_produto = secondUserMessage ? extractNumber(secondUserMessage) : null;

// 3ª mensagem do usuário = escolha do serviço
const thirdUserMessage = userMessages[2] ?? null;
const serviceChoice = thirdUserMessage ? extractNumber(thirdUserMessage) : null;

// opcao_servico e id_servico só existem quando já houver 2ª e 3ª mensagem do usuário
let opcao_servico = null;
let id_servico = null;

if (id_produto !== null && serviceChoice !== null) {
  opcao_servico = Number(`${id_produto}${serviceChoice}`);
  id_servico = opcao_servico;
}

return [
  {
    json: {
      ...row,
      id_produto,
      opcao_servico,
      id_servico
    }
  }
];

const items = $input.all();

// ================================
// CONFIG
// ================================
const SLOT_MINUTES = 30;

const PERIODOS = [
  { start: "07:00", end: "11:00" },
  { start: "13:00", end: "18:00" },
];

// ================================
// HELPERS
// ================================
function timeToMinutes(timeStr) {
  const [h, m] = String(timeStr).split(":").map(Number);
  return (h * 60) + m;
}

function minutesToTime(minutes) {
  const h = Math.floor(minutes / 60);
  const m = minutes % 60;
  return String(h).padStart(2, "0") + ":" + String(m).padStart(2, "0");
}

function extractTime(value) {
  if (!value) return null;

  // Se já vier como "07:30"
  if (/^\d{2}:\d{2}$/.test(String(value))) {
    return String(value);
  }

  // Se vier ISO tipo "2026-03-24T07:30:00.000Z"
  const str = String(value);
  const match = str.match(/T(\d{2}:\d{2})/);
  if (match) return match[1];

  return null;
}

// ================================
// HORÁRIOS OCUPADOS
// ================================
// Ajuste aqui o nome do campo que vem do Airtable
// Ex.: data_hora, horario, slot, start_time...
const occupiedSlots = items
  .map(item => {
    const json = item.json || {};
    return (
      extractTime(json.horario) ||
      extractTime(json.data_hora) ||
      extractTime(json.slot) ||
      extractTime(json.start_time)
    );
  })
  .filter(Boolean);

// Para busca rápida
const occupiedSet = new Set(occupiedSlots);

// ================================
// GERA TODOS OS SLOTS POSSÍVEIS
// ================================
const availableSlots = [];

for (const periodo of PERIODOS) {
  let current = timeToMinutes(periodo.start);
  const end = timeToMinutes(periodo.end);

  while (current < end) {
    const slot = minutesToTime(current);

    if (!occupiedSet.has(slot)) {
      availableSlots.push({
        horario: slot,
        periodo: `${periodo.start}-${periodo.end}`,
      });
    }

    current += SLOT_MINUTES;
  }
}

// ================================
// OUTPUT
// ================================
return availableSlots.map(slot => ({
  json: slot,
}));

const items = $input.all();

// emojis de 1 a 10
const baseEmojis = ["1️⃣","2️⃣","3️⃣","4️⃣","5️⃣","6️⃣","7️⃣","8️⃣","9️⃣","🔟"];

function getEmoji(index) {
  const number = index + 1;

  if (number <= 10) {
    return baseEmojis[index];
  }

  return `${number}️⃣`;
}

// pega horários válidos
const horarios = items
  .map(item => item.json?.horario)
  .filter(Boolean);

// se não tiver horários
if (horarios.length === 0) {
  return [
    {
      json: {
        message: "No momento, não há horários disponíveis para hoje.\n\nSe preferir, posso verificar outro dia ou encaminhar você para atendimento direto no WhatsApp.",
        options_map: {}
      }
    }
  ];
}

// monta linhas numeradas
const linhas = horarios.map((horario, index) => {
  return `${getEmoji(index)} ${horario}`;
});

// cria mapa de opção -> horário
const optionsMap = {};
horarios.forEach((horario, index) => {
  optionsMap[String(index + 1)] = horario;
});

// mensagem final
const message =
  `Perfeito! Estes são os horários disponíveis para hoje:\n\n` +
  `${linhas.join("\n")}\n\n` +
  `✍️ Responda apenas com o número da opção desejada.`;

return [
  {
    json: {
      message,
      options_map: optionsMap,
      horarios_disponiveis: horarios
    }
  }
];

const item = $json;

// =====================================================
// CAMPOS DE ENTRADA
// =====================================================
const opcao = String(item.preferencial_data || "").trim();
const session = item.session || null;

// Se no futuro vier uma data manual digitada pelo usuário,
// você pode alimentar esse campo antes deste node.
const dataManual = String(item.data_informada || "").trim();

// =====================================================
// HELPERS
// =====================================================
function formatDateLocal(date) {
  const year = date.getFullYear();
  const month = String(date.getMonth() + 1).padStart(2, "0");
  const day = String(date.getDate()).padStart(2, "0");
  return `${year}-${month}-${day}`;
}

function addDays(date, days) {
  const d = new Date(date);
  d.setDate(d.getDate() + days);
  return d;
}

function parseBRDate(br) {
  const match = br.match(/^(\d{2})\/(\d{2})\/(\d{4})$/);
  if (!match) return null;

  const [, dd, mm, yyyy] = match;
  return `${yyyy}-${mm}-${dd}`;
}

// =====================================================
// REGRA DE DATA
// =====================================================
const now = new Date();

let preferencia_data = null;
let data_desejada = null;
let precisa_pedir_data = false;

if (opcao === "HOJE" || opcao === "1") {
  preferencia_data = "HOJE";
  data_desejada = formatDateLocal(now);
} else if (opcao === "AMANHA" || opcao === "2") {
  preferencia_data = "AMANHA";
  data_desejada = formatDateLocal(addDays(now, 1));
} else if (opcao === "OUTRA_DATA" || opcao === "3") {
  preferencia_data = "OUTRA_DATA";

  if (dataManual) {
    data_desejada = parseBRDate(dataManual);
  } else {
    precisa_pedir_data = true;
  }
}

// =====================================================
// OUTPUT
// =====================================================
return [
  {
    json: {
      ...item,
      session,
      preferencia_data,
      data_desejada,
      precisa_pedir_data
    }
  }
];

const items = $input.all();

// ================================
// CONFIG
// ================================
const SLOT_MINUTES = 30;

const PERIODOS = {
  MANHA: { start: "07:00", end: "11:00" },
  TARDE: { start: "13:00", end: "18:00" },
};

// ================================
// HELPERS
// ================================
function timeToMinutes(timeStr) {
  const [h, m] = String(timeStr).split(":").map(Number);
  return (h * 60) + m;
}

function minutesToTime(minutes) {
  const h = Math.floor(minutes / 60);
  const m = minutes % 60;
  return String(h).padStart(2, "0") + ":" + String(m).padStart(2, "0");
}

function extractTime(value) {
  if (!value) return null;

  const str = String(value);

  if (/^\d{2}:\d{2}$/.test(str)) {
    return str;
  }

  const match = str.match(/T(\d{2}:\d{2})/);
  if (match) return match[1];

  return null;
}

function gerarSlotsPeriodo(start, end, slotMinutes = 30) {
  const slots = [];
  let current = timeToMinutes(start);
  const limit = timeToMinutes(end);

  while (current < limit) {
    slots.push(minutesToTime(current));
    current += slotMinutes;
  }

  return slots;
}

function formatarDataHumana(itemBase) {
  const pref =
    itemBase.preferencia_data ||
    itemBase.preferencial_data ||
    null;

  if (pref === "HOJE") return "hoje";
  if (pref === "AMANHA") return "amanhã";

  const dataDesejada = itemBase.data_desejada || null;
  if (dataDesejada && /^\d{4}-\d{2}-\d{2}$/.test(dataDesejada)) {
    const [yyyy, mm, dd] = dataDesejada.split("-");
    return `${dd}/${mm}/${yyyy}`;
  }

  return "a data desejada";
}

// ================================
// ITEM BASE
// ================================
const itemBase = items[0]?.json || {};

// ================================
// HORÁRIOS OCUPADOS
// ================================
const occupiedSlots = items
  .map(item => {
    const json = item.json || {};
    return (
      extractTime(json["Data e Hora de Início"]) ||
      extractTime(json.inicio) ||
      extractTime(json.horario) ||
      extractTime(json.data_hora) ||
      extractTime(json.slot) ||
      extractTime(json.start_time)
    );
  })
  .filter(Boolean);

const occupiedSet = new Set(occupiedSlots);

// ================================
// GERA SLOTS POSSÍVEIS
// ================================
const slotsManha = gerarSlotsPeriodo(PERIODOS.MANHA.start, PERIODOS.MANHA.end, SLOT_MINUTES);
const slotsTarde = gerarSlotsPeriodo(PERIODOS.TARDE.start, PERIODOS.TARDE.end, SLOT_MINUTES);

// ================================
// DISPONÍVEIS
// ================================
const disponiveisManha = slotsManha.filter(slot => !occupiedSet.has(slot));
const disponiveisTarde = slotsTarde.filter(slot => !occupiedSet.has(slot));

const temManha = disponiveisManha.length > 0;
const temTarde = disponiveisTarde.length > 0;

// ================================
// MENSAGEM
// ================================
const dataHumana = formatarDataHumana(itemBase);

let reply = "";
let opcoes_periodo = [];

if (temManha && temTarde) {
  reply =
    `Perfeito! Confirmei na nossa agenda e temos horários disponíveis para ${dataHumana} 😊\n\n` +
    `Você prefere vir em qual período?\n\n` +
    `1️⃣ Manhã\n\n` +
    `2️⃣ Tarde\n\n` +
    `✍️ Responda apenas com o número da opção desejada.`;

  opcoes_periodo = [
    { opcao: "1", periodo: "MANHA" },
    { opcao: "2", periodo: "TARDE" }
  ];
} else if (temManha && !temTarde) {
  reply =
    `Perfeito! Confirmei na nossa agenda e temos horários disponíveis para ${dataHumana} apenas no período da manhã 😊\n\n` +
    `Se desejar continuar com esse período, responda:\n\n` +
    `1️⃣ Manhã\n\n` +
    `Se preferir, você também pode escolher outra data.\n\n` +
    `3️⃣ Outra data\n\n` +
    `✍️ Responda apenas com o número da opção desejada.`;

  opcoes_periodo = [
    { opcao: "1", periodo: "MANHA" },
    { opcao: "3", periodo: "OUTRA_DATA" }
  ];
} else if (!temManha && temTarde) {
  reply =
    `Perfeito! Confirmei na nossa agenda e temos horários disponíveis para ${dataHumana} apenas no período da tarde 😊\n\n` +
    `Se desejar continuar com esse período, responda:\n\n` +
    `2️⃣ Tarde\n\n` +
    `Se preferir, você também pode escolher outra data.\n\n` +
    `3️⃣ Outra data\n\n` +
    `✍️ Responda apenas com o número da opção desejada.`;

  opcoes_periodo = [
    { opcao: "2", periodo: "TARDE" },
    { opcao: "3", periodo: "OUTRA_DATA" }
  ];
} else {
  reply =
    `Verifiquei nossa agenda e não encontrei horários disponíveis para ${dataHumana} 😕\n\n` +
    `Você pode escolher outra data:\n\n` +
    `3️⃣ Outra data\n\n` +
    `✍️ Responda apenas com o número da opção desejada.`;

  opcoes_periodo = [
    { opcao: "3", periodo: "OUTRA_DATA" }
  ];
}

// ================================
// OUTPUT
// ================================
return [
  {
    json: {
      ...itemBase,
      horarios_ocupados: occupiedSlots,
      disponiveis_manha: disponiveisManha,
      disponiveis_tarde: disponiveisTarde,
      tem_manha: temManha,
      tem_tarde: temTarde,
      opcoes_periodo,
      reply,
    },
  },
];

const item = $json;

// =====================================================
// CAMPOS DE ENTRADA
// =====================================================
const opcao = String(item.preferencial_data || "").trim();
const session = item.session || null;

// Se no futuro vier uma data manual digitada pelo usuário,
// você pode alimentar esse campo antes deste node.
const dataManual = String(item.data_informada || "").trim();

// =====================================================
// HELPERS
// =====================================================
function formatDateLocal(date) {
  const year = date.getFullYear();
  const month = String(date.getMonth() + 1).padStart(2, "0");
  const day = String(date.getDate()).padStart(2, "0");
  return `${year}-${month}-${day}`;
}

function addDays(date, days) {
  const d = new Date(date);
  d.setDate(d.getDate() + days);
  return d;
}

function parseBRDate(br) {
  const match = br.match(/^(\d{2})\/(\d{2})\/(\d{4})$/);
  if (!match) return null;

  const [, dd, mm, yyyy] = match;
  return `${yyyy}-${mm}-${dd}`;
}

