const items = $input.all();

// ================================
// CONFIG
// ================================
const SLOT_MINUTES = 30;

const PERIODOS = {
  MANHA: { start: "07:00", end: "11:00" },
  TARDE: { start: "13:00", end: "18:00" },
};

// ================================
// HELPERS
// ================================
function timeToMinutes(timeStr) {
  const [h, m] = String(timeStr).split(":").map(Number);
  return (h * 60) + m;
}

function minutesToTime(minutes) {
  const h = Math.floor(minutes / 60);
  const m = minutes % 60;
  return `${String(h).padStart(2, "0")}:${String(m).padStart(2, "0")}`;
}

function extractTime(value) {
  if (!value) return null;

  const str = String(value);

  // Ex.: "07:30"
  if (/^\d{2}:\d{2}$/.test(str)) {
    return str;
  }

  // Ex.: "2026-03-25T07:30:00.000Z"
  const match = str.match(/T(\d{2}:\d{2})/);
  if (match) return match[1];

  return null;
}

function gerarSlotsPeriodo(start, end, slotMinutes = 30) {
  const slots = [];
  let current = timeToMinutes(start);
  const limit = timeToMinutes(end);

  while (current < limit) {
    slots.push(minutesToTime(current));
    current += slotMinutes;
  }

  return slots;
}

function detectarPeriodoPorSignificado(significado) {
  const s = String(significado || "").toLowerCase();

  if (s.includes("manha")) return "MANHA";
  if (s.includes("tarde")) return "TARDE";

  return null;
}

function formatarDataHumana(itemBase) {
  const pref =
    itemBase.preferencia_data ||
    itemBase.preferencial_data ||
    null;

  if (pref === "HOJE") return "hoje";
  if (pref === "AMANHA") return "amanhã";

  const dataDesejada = itemBase.data_desejada || null;
  if (dataDesejada && /^\d{4}-\d{2}-\d{2}$/.test(dataDesejada)) {
    const [yyyy, mm, dd] = dataDesejada.split("-");
    return `${dd}/${mm}/${yyyy}`;
  }

  return "a data desejada";
}

// ================================
// ITEM BASE
// ================================
// Procuramos o item que tem "significado"
const itemBase = items.find(i => i.json?.significado)?.json || items[0]?.json || {};

// ================================
// IDENTIFICAR PERÍODO PELO SIGNIFICADO
// ================================
const periodoIdentificado = detectarPeriodoPorSignificado(itemBase.significado);

if (!periodoIdentificado) {
  return [
    {
      json: {
        ...itemBase,
        erro: true,
        reply:
          "Não consegui identificar se o período escolhido é manhã ou tarde.",
      },
    },
  ];
}

// ================================
// PEGAR HORÁRIOS OCUPADOS DO AIRTABLE
// ================================
const occupiedSlots = items
  .map(item => {
    const json = item.json || {};
    return (
      extractTime(json["Data e Hora de Início"]) ||
      extractTime(json.inicio) ||
      extractTime(json.horario) ||
      extractTime(json.data_hora) ||
      extractTime(json.slot) ||
      extractTime(json.start_time)
    );
  })
  .filter(Boolean);

const occupiedSet = new Set(occupiedSlots);

// ================================
// GERAR SLOTS DO PERÍODO ESCOLHIDO
// ================================
const faixa = PERIODOS[periodoIdentificado];
const todosSlots = gerarSlotsPeriodo(faixa.start, faixa.end, SLOT_MINUTES);

const horariosDisponiveis = todosSlots.filter(slot => !occupiedSet.has(slot));

// ================================
// MONTAR OPÇÕES NUMERADAS
// ================================
const opcoes_horarios = horariosDisponiveis.map((horario, index) => ({
  opcao: String(index + 1),
  horario,
  periodo: periodoIdentificado,
}));

// ================================
// MENSAGEM
// ================================
const tituloPeriodo = periodoIdentificado === "MANHA" ? "manhã" : "tarde";
const dataHumana = formatarDataHumana(itemBase);

let reply = "";

if (horariosDisponiveis.length === 0) {
  reply =
    `Verifiquei nossa agenda e não encontrei horários disponíveis para ${dataHumana}, no período da ${tituloPeriodo} 😕\n\n` +
    `Você pode escolher outro período ou outra data.`;
} else {
  const lista = opcoes_horarios
    .map(item => `${item.opcao}️⃣ ${item.horario}`)
    .join("\n\n");

  reply =
    `Perfeito! Estes são os horários disponíveis para ${dataHumana}, no período da ${tituloPeriodo} 😊\n\n` +
    `${lista}\n\n` +
    `✍️ Responda apenas com o número do horário desejado.`;
}

// ================================
// OUTPUT
// ================================
return [
  {
    json: {
      ...itemBase,
      periodo: periodoIdentificado,
      horarios_ocupados: occupiedSlots,
      horarios_disponiveis: horariosDisponiveis,
      opcoes_horarios,
      reply,
    },
  },
];

