function extrairHorarioDoSignificado(significado) {
  const texto = String(significado || "");
  const match = texto.match(/(\d{2}:\d{2})/);
  return match ? match[1] : null;
}

function somarMinutos(horario, minutos) {
  const [h, m] = String(horario).split(":").map(Number);
  const total = (h * 60) + m + minutos;
  const novaHora = Math.floor(total / 60);
  const novoMin = total % 60;

  return `${String(novaHora).padStart(2, "0")}:${String(novoMin).padStart(2, "0")}`;
}

// ================================
// DADOS
// ================================
const data = item.preferencia_data || null;
const horaInicio = extrairHorarioDoSignificado(item.significado);
const horaFim = horaInicio ? somarMinutos(horaInicio, 30) : null;

// Formato ISO sem timezone forçado
const dataHoraInicio = (data && horaInicio) ? `${data}T${horaInicio}:00` : null;
const dataHoraFim = (data && horaFim) ? `${data}T${horaFim}:00` : null;

