const messages = $json.session?.messages || [];

// ================================
// ENCONTRAR ÚLTIMA MENSAGEM DO ASSISTANT
// ================================
let lastAssistantIndex = -1;

for (let i = messages.length - 1; i >= 0; i--) {
  if (messages[i].role === "assistant") {
    lastAssistantIndex = i;
    break;
  }
}

// ================================
// PEGAR RESPOSTAS NUMÉRICAS DO USER APÓS A ÚLTIMA PERGUNTA
// ================================
let respostas = "";

for (let i = lastAssistantIndex + 1; i < messages.length; i++) {
  const msg = messages[i];

  if (msg.role === "user") {
    const numeros = String(msg.text || "").replace(/\D/g, "");

    if (numeros) {
      respostas += numeros;
    }
  }
}

// ================================
// OUTPUT MANTENDO O JSON ANTERIOR
// ================================
return [
  {
    json: {
      ...$json,
      respostas_concatenadas: respostas,
      total_respostas: respostas.length,
    },
  },
];
